const job = $('Claim Due Jobs').item.json;
const ctx = $input.item.json;

const profile = typeof ctx.user_profile === 'string' ? JSON.parse(ctx.user_profile) : (ctx.user_profile || {});
const programPlan = typeof ctx.program_plan === 'string' ? JSON.parse(ctx.program_plan) : (ctx.program_plan || {});
const templateKey = job.template_key;

const weekMatch = templateKey.match(/^week_(\d+)$/);
const weekNum = weekMatch ? parseInt(weekMatch[1]) : null;

const pickImageUrl = (ex = {}) => ex.image_url || ex.imageUrl || ex.image || ex.photo_url || ex.photoUrl || '';
const mapExercise = (ex) => ex ? { name: ex.name, description: ex.description, image_url: pickImageUrl(ex), cues: ex.cues } : null;

let weekPlanForPdf = {};
if (weekNum) {
  const weekPlan = programPlan[`week_${weekNum}`] || {};
  const sessions = ['morning', 'midday', 'afternoon', 'evening'];
  for (const s of sessions) {
    const slot = weekPlan[s] || {};
    weekPlanForPdf[s] = { warmup: mapExercise(slot.warmup), main: mapExercise(slot.main) };
  }
}

const calendarMap = {
  1: $env.CALENDAR_WEEK1_URL || '',
  2: $env.CALENDAR_WEEK2_URL || '',
  3: $env.CALENDAR_WEEK3_URL || '',
  4: $env.CALENDAR_WEEK4_URL || ''
};
const calendarUrl = (weekNum ? calendarMap[weekNum] : null) || $env.CALENDAR_DEFAULT_URL || '';

const fill = (str, vars) => String(str || '').replace(/{{\s*([a-zA-Z0-9_]+)\s*}}/g, (_, key) => vars[key] ?? '');

const vars = {
  Name: ctx.name || 'there',
  name: ctx.name || 'there',
  week_number: weekNum || '',
  calendar_url: calendarUrl,
  week_pdf_url: '',
  level2_offer_url: $env.LEVEL2_OFFER_URL || '',
  feedback_url: $env.FEEDBACK_FORM_URL || '',
  goal: profile.primary_goal || profile.goal || ''
};

return {
  json: {
    job_id: job.job_id,
    lead_id: job.lead_id,
    email: job.email,
    template_key: templateKey,
    sequence_key: job.sequence_key,
    name: ctx.name,
    week_number: weekNum,
    week_plan: weekPlanForPdf,
    profile,
    calendar_url: calendarUrl,
    requires_pdf: ctx.requires_pdf,
    email_subject: fill(ctx.tpl_subject, vars),
    email_html: fill(ctx.tpl_html, vars),
    attachment_filename: weekNum ? `week${weekNum}-plan.pdf` : `mdt-${templateKey}.pdf`
  }
};

const payload = $('Build Email Payload').item.json;
return {
  json: {
    ...payload,
    attachments: [{ filename: payload.attachment_filename, content: $json.pdf }]
  }
};
